UPDATE TRAVEL_LIST 
SET 
    TRAVEL_TITLE      = #{travelTitle},
    TRAVEL_START_DATE = #{travelStartDate, jdbcType=DATE}, 
    TRAVEL_END_DATE   = #{travelEndDate, jdbcType=DATE}
