UPDATE TRAVEL_LIST_SUB SET CONTENT_TITLE = #{contentTitle, jdbcType=VARCHAR}, RATING = #{rating, jdbcType=INTEGER},
TRAVEL_SUB_CONTENT = NVL(#{travelSubContent, jdbcType=VARCHAR}, TRAVEL_SUB_CONTENT)
WHERE TRAVEL_SUB_NO = #{travelSubNo, jdbcType=INTEGER}

UPDATE TRAVEL_LIST
SET status = 'N'
WHERE travel_no = #{travelNo}
